var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"<color=#ffd34c>에스테로사 드 슈발리에.</color>","JPN":"<color=#ffd34c>エステロサ・ド・シュヴァリエ。</color>","ENG":"<color=#ffd34c>Esterosa de Chevalier.</color>","TWN":"<color=#ffd34c>聖騎士艾斯特洛索</color>"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"지금부터, 그녀의 <color=#ffd34c>기사단장직 박탈</color>에 관한 회의를 시작한다.","JPN":"これより、彼女の<color=#ffd34c>騎士団長職剥奪</color>に関する会議を始める。","ENG":"We will now begin deliberation on the <color=#ffd34c>dismissal of her position as Knight Captain</color>.","TWN":"現在開始，關於她的<color=#ffd34c>騎士團長職務剝奪</color>的會議。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잠깐. 그게 대체 무슨 말씀이십니까, 프레이더 경!","JPN":"待ってください、どういうことですか、フレイダー卿！","ENG":"Wait. What are you saying, Sir Frayder?!","TWN":"等一下。那到底是什麼意思，弗雷德！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그래. 기사단장직 박탈이라는 게 대체 무슨 소리야?","JPN":"そ、そうだよ。騎士団長職剥奪って、どういうこと？","ENG":"Y-yeah! What's this about removing her as captain?","TWN":"被剝奪騎士團長職務到底是什麼意思？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"클리포트 게임에 참전한 건 우리 선택이었어. 책임을 묻는다면 연대책임이라고!","JPN":"クリフォトゲームに参戦したのは私たちの選択だった。責任を問うとしたら連帯責任だよ！","ENG":"We joined the Qliphoth Game of our own accord. If there's blame to place, it's on all of us!","TWN":"參與逆卡巴拉遊戲是我們的選擇。如果要追究責任，那就是連帶責任！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"리브 경. 기사들의 부덕함을 다스리는 것 또한 단장으로서의 역할이네.","JPN":"リブ卿。騎士たちの不徳を正すこともまた、団長としての務めだ。","ENG":"Dame Liv, upholding the discipline of the knights is also part of a captain's duty.","TWN":"莉芙。管理騎士們的不端行為也是作為團長的職責。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 그래도 이건 너무 갑작스럽잖아!","JPN":"でもこれはいきなりすぎるよ！","ENG":"Still, this is way too sudden!","TWN":"不，這也太突然了吧！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리, 리브 언니. 주변 시선이 이상해요…….","JPN":"リ、リブさん。周りの視線が変です……","ENG":"L-Liv... People are staring...","TWN":"莉，莉芙姊姊。周圍的目光有些奇怪……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……당했군요. 해당 안건이 대두된 것만으로도 상황은 저희에게 불리하게 작용됩니다.","JPN":"……やられましたね。この案件が取り上げられたという事実だけでも、状況は私たちにとって不利に働きます。","ENG":"...They got us. The moment this motion was raised, the situation turned against us.","TWN":"……被算計了。僅僅是這個議題被提出來，情況就對我們不利。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이 버밍엄 교수와 각별한 사이셨으니, 현 상황을 기점으로 의구심을 품는 기사들이 늘어나겠죠.","JPN":"団長がバーミンガム教授と格別な仲だった分、現状況をもって疑いを抱く騎士は増えるでしょう。","ENG":"Given her close ties with Professor Birmingham, this will only fuel doubt among the knights.","TWN":"團長你與伯明罕教授關係密切，現狀可能會引發更多懷疑的報導。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그럼 이제 어떡하죠?","JPN":"じゃ、じゃあこれからどうすれば？","ENG":"Th-then what do we do now?","TWN":"那，那現在怎麼辦？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……한 가지. 묻고 싶은 게 있습니다, 프레이더 경.","JPN":"……1つ、お尋ねしたいことがあります。フレイダー卿。","ENG":"...One question, Sir Frayder.","TWN":"……有一件事。我想問一下，弗雷德。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"원로원은 저희들의 판단이 잘못되었다 생각하십니까?","JPN":"元老院は私たちの判断が間違っていたとお考えですか？","ENG":"Does the Council believe our judgment was wrong?","TWN":"元老院認為我們的判斷是錯誤的嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"통제되지 않는 검의 위험성은 이미 레드시프트로 인해 통감되었네.","JPN":"統制の利かない剣の危険性は、すでにレッドシフトの件で痛感している。","ENG":"We've already seen the dangers of unchecked blades. Red Shift taught us that well.","TWN":"不受控制的劍的危險性已經通過紅移深刻感受到了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"관리국과 원로원의 지시를 동시에 저버리는 순간, 자네도 나름의 각오를 했겠지.","JPN":"管理局と元老院の指示を同時に無視した瞬間、君もそれなりの覚悟はしただろう。","ENG":"When you defied both the Administration and the Council's orders, I assume you knew what that meant.","TWN":"當你同時違背管理局和元老院的指示時，你也做好了自己的覺悟吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"누군가를 구하는 행위를 망설이지 말게.","JPN":"誰かを救うことを躊躇うな。","ENG":"Never hesitate to save someone.","TWN":"切勿猶豫去做拯救他人的事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그로 인해 책임을 져야 할 순간이 올지라도, 그건 결코 잘못된 행동이 아니야.","JPN":"そのことで責任を問われることになろうとも、それは決して間違った行動ではない。","ENG":"Even if it brings consequences, that alone is never the wrong choice.","TWN":"即便因此需要承擔責任，那也絕不是錯誤的行為。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……わかりました。","ENG":"...Understood.","TWN":"……我知道了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그게 원로원의 판단이라면 따르겠습니다.","JPN":"それが元老院の判断であるなら、従います。","ENG":"If that is the Council's judgment, I will abide by it.","TWN":"如果那是元老院的決定，我會遵從。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님, 그게 무슨 말씀이십니까!?","JPN":"団長、どういうことですか？","ENG":"Captain, what are you saying?!","TWN":"團長，你在說什麼啊！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 전통에 예외란 없네, 부단장.","JPN":"騎士団の伝統に例外はない、副団長。","ENG":"There are no exceptions in the Order's traditions, Deputy.","TWN":"騎士團的傳統沒有例外，副團長。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"달리 사태를 수습할 방법이 없다는 걸 그대도 알고 있지 않나.","JPN":"事態を収拾できる方法が他にないということぐらい、君も知っているだろう。","ENG":"You know there's no other way to resolve this.","TWN":"你也知道沒有其他辦法來解決這個問題吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"그 말 대로다. 원로원의 판단이 선 이상 해당 안건의 결정을 늦출 필요는 없지.","JPN":"その通りだ。元老院の判断が下されたのなら、これ以上決定を躊躇う必要はない。","ENG":"She's right. Since the Council has already ruled, there's no point delaying the decision.","TWN":"正如你所說，既然元老院已經做出了判斷，就沒有必要推遲該議案的決定。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"별을 추종하는 슈레이더의 제프. 원로원의 판단에 동의한다!","JPN":"星の追従者、シュレイダーのジェフ。元老院の判断に同意する！","ENG":"Jeff of House Schrader, follower of the stars. I support the Council's judgment!","TWN":"我，追隨星辰的許瑞德·傑夫，贊同元老院的判斷！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"버고 소드의 결백이 두 번씩이나 같은 피에 더럽혀진 상황에서.","JPN":"ヴァルゴソードの潔白が二度も同じ血筋によって汚された状況で。","ENG":"The Virgo Sword has been stained with the same blood twice now.","TWN":"布林加夫之劍的純潔竟兩次被同樣的血玷污。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"하물며, 마왕의 사도가 기사단에 들인 자를 어찌 따를 수 있겠는가!!","JPN":"ましてや、魔王の使徒が騎士団に迎え入れた者など、誰が従えるというのだ！！","ENG":"How can we follow someone brought in by a Demon Lord's Apostle?!","TWN":"更何況，怎麼能跟隨讓魔王的使徒加入騎士團的人！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"제프 경의 말이 옳다! 그녀는 평기사 자격도 갖추지 못한 채 단장직에 오르지 않았는가!","JPN":"ジェフ卿の言う通りだ！　彼女は平騎士の資格すら持たない身で団長職に就いたではないか！","ENG":"Sir Jeff is right! She wasn't even qualified as a knight bachelor when she took command!","TWN":"傑夫卿說得對！她連平民騎士的資格都沒有，卻登上了團長之位！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHEER"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"혼란스러운 시대에 신분도 자질도 불분명한 자를 단장으로 놔둘 순 없다!!","JPN":"この混乱のご時世、身分も資質も不確かな者にこれ以上団長を任せるわけにはいかない！！","ENG":"In these chaotic times, we can't have a leader with no clear status or merit!","TWN":"在這個混亂的時代，身份和資質都不明確的人不能被任命為團長！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"신분이나 자질에 얽매일 필요는 없네.","JPN":"身分や資質に囚われる必要はない。","ENG":"There's no need to cling to titles or background.","TWN":"不必拘泥於身份或資質。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네가 기사로서의 신념을 지켜나간다면, 동료들은 자연스레 그 뒤를 따르게 될 거야.","JPN":"君が騎士としての信念を貫き続けるのなら、仲間たちは自ずとその背を追うようになるだろう。","ENG":"If you live by your conviction as a knight, others will naturally follow.","TWN":"如果你能堅持作為騎士的信念，夥伴們自然會跟隨你。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"별을 추종하는 앨런의 리브. 아저씨들의 판단에 반대한다!","JPN":"星の追従者、アレンのリブ。おじさんたちの判断に反対する！","ENG":"Liv of House Allen, follower of the stars. I oppose the Elders' judgment!","TWN":"追隨星辰的艾倫。反對叔叔們的判斷！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"버고 소드를 뽑은 시점에서 단장은 단장이야! 이제 와서 다른 소리해도 곤란하다고!!","JPN":"ヴァルゴソードを抜いた時点から団長は団長だ！　今更そんなことを言われても困るんだよ！","ENG":"The moment she drew the Virgo Sword, she was our captain! You can't backtrack now!","TWN":"從拔出布林加夫之劍的那一刻起，你就是團長了！現在再說其他話也沒用！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"맞습니다. 단장직은 별의 선택을 통해 선별된 자리예요.","JPN":"そうです。団長職は星によって選択されたものです。","ENG":"Exactly. The position of captain is chosen by the stars.","TWN":"沒錯。團長職位是透過星星的選擇來決定的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"설령 원로분들이라 한들, 단장님의 자격을 부정할 순 없습니다!","JPN":"たとえ元老院であれ、団長の資格を否定することはできません！","ENG":"Not even the Elders can deny that!","TWN":"即便是元老們，也無法否定團長的資格！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이럴 게 아니라 분명 대화로 해결할 수 있을 거예요…….","JPN":"こ、こんなやり方じゃなくて、きっと話し合いで解決できるはずです……","ENG":"W-we can work this out through dialogue, I'm sure...","TWN":"這，這樣不行，我們一定可以通過對話解決的……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"별을 추종하는 로웰의 피오네. 마찬가지로 원로원의 판단에 반대합니다.","JPN":"星の追従者、ローウェルのフィオネ。同じく元老院の判断に反対します。","ENG":"Fione of House Lowell, follower of the stars. I also oppose the Council's judgment.","TWN":"追隨星辰的菲奧尼·勞威爾。我同樣反對元老院的判斷。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"현 세대 중 에스테로사 경을 제외한 그 누구도 버고 소드의 선택을 받지 못한 상황에서.","JPN":"エステロサ卿を除き、現世代では誰もヴァルゴソードに選ばれていません。","ENG":"Esterosa is the only one in our generation chosen by the Virgo Sword.","TWN":"在現世代中，除了艾斯特洛索，沒有任何人被布林加夫之劍選中。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"갑작스러운 단장의 부재는 기사단의 결속을 흔들리게 할 뿐입니다.","JPN":"こんな時に団長の座を空席にするのは、騎士団の結束を揺るがすだけです。","ENG":"Removing her suddenly will only divide the Order.","TWN":"團長的突然缺席只會動搖騎士團的團結。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로분들께서는 부디 판단을 재고하여-.","JPN":"元老院はどうか考え直して……","ENG":"Please, reconsider–","TWN":"請各位元老重新考慮——。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"여전히 답답한 소리를 하는구나, 피오네.","JPN":"相変わらず頭の固い子ね、フィオネ。","ENG":"Still spouting nonsense, are you, Fione?","TWN":"你還是在說一些讓人無語的話呢，菲奧尼。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"한심해. 가문을 대표하는 기사가 되었는데도 다른 누군가를 추종하는 꼴이라니.","JPN":"情けない。ローウェル家を代表する騎士になっても他人の後ろを付いて回ってるなんて。","ENG":"Pathetic. You represent your house and yet you follow another like a lost dog.","TWN":"真是可悲。明明已經成為代表家族的騎士，卻還要追隨其他人。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"지금 네 꼴은 기사가 아니라 주인을 따르는 맹목적인 개와 같구나.","JPN":"今のあなたは騎士なんかじゃなくて、飼い主に従う盲目的な犬同然よ。","ENG":"You're not a knight, you're a mutt blindly obeying a master.","TWN":"現在你的樣子就像是追隨主人的盲目之犬，而不是騎士。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"어, 언니? 지금 대체 무슨 소리를 하시는 건가요?","JPN":"ね、姉さん？　何を言うんですか？","ENG":"C-Carrie?! What are you talking about?!","TWN":"呃，姊姊？你現在到底在說什麼呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"무슨 소리냐니. 너도 알고 있잖아?","JPN":"何って、あなたもわかっているでしょう？","ENG":"You know exactly what I mean.","TWN":"說什麼？你也知道的吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"균형의 천칭자리, 자애의 물병자리와 같이 각 무구에는 고유한 성질의 별빛이 존재해.","JPN":"均衡の天秤座、慈愛の水瓶座のように、それぞれの武具には固有の性質を持つ星の光があるの。","ENG":"Each Armament bears the unique starlight of its sign. Like the balance of Libra or the compassion of Aquarius.","TWN":"平衡的天秤座，慈愛的水瓶座，每個武器都有其獨特性質的星光。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"그 힘을 다룬다는 건 가문을 대표하는 것을 넘어 기사도의 일부를 주관한다는 거지.","JPN":"その力を扱うということは、家を代表するだけじゃなくて、騎士道の一部を司るということ。","ENG":"To wield that power is to embody chivalry, not just represent a house.","TWN":"掌握那股力量不僅意味著代表家族，還意味著掌管騎士精神的一部分。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"그런데… 정의를 주관해야 할 버고 소드의 보유자가 원로원의 판단을 거슬렀다.","JPN":"それなのに……正義を司るべきヴァルゴソードの所持者が、元老院の判断に逆らった。","ENG":"But now... the bearer of the Virgo Sword, who should uphold justice, defies the Council.","TWN":"但是……應該主持正義的布林加夫之劍的持有者違背了元老院的判斷。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"전통을 지켜온 기사단이 이걸 덤덤히 받아들일 수 있을 거라 생각하는 건가?","JPN":"伝統を重んじる騎士団が、これを簡単に受け入れると思う？","ENG":"Do you really think the Order, steeped in tradition, will accept that?","TWN":"你認為那些堅守傳統的騎士團會坦然接受這一切嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 앞서 말했듯 버고 소드의 힘을 다룰 수 있는 건 단장님뿐입니다!","JPN":"ですが先程も言ったように、ヴァルゴソードの力を扱えるのは団長だけです！","ENG":"But like I said, she's the only one who can wield the Virgo Sword!","TWN":"但是正如之前所說，能夠駕馭布林加夫之劍力量的只有團長！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"그녀만이 버고 소드를 다룰 수 있기에 현 사안의 중요성이 부각되는 거야.","JPN":"彼女だけがヴァルゴソードを扱えるからこそ、この案件は深刻に取り上げられているの。","ENG":"Which is exactly why this issue is so serious.","TWN":"只有她能使用布林加夫之劍，因此當前事件的重要性才得以凸顯。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"막말로, 그녀의 이번 독단이 개인의 영달을 추구하는 레드시프트와 다를 게 뭐가 있지?","JPN":"はっきり言って、彼女の独断が個人の繁栄を追求するレッドシフトと何が違う？","ENG":"Honestly, how is her reckless defiance any different from Red Shift's pursuit of personal profit?","TWN":"說實話，她這次的獨斷行為和追求個人榮耀的紅移有什麼區別？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"언동에 주의해 주십시오! 아무리 언니라도 단장님을 모욕하는 건……!!","JPN":"口を謹んでください！　いくら姉さんでも団長を侮辱すれば……！！","ENG":"Watch your words! Even if you are my sister, I won't tolerate you insulting our captain...!","TWN":"請注意你的言行！即使是姊姊，也不能侮辱團長……！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"그만. 둘 다 거기까지.","JPN":"二人ともよせ。","ENG":"Enough. Both of you.","TWN":"夠了。你們兩個到此為止。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"유감스러우나 피오네 경. 본 안건에 열두 원로의 뜻은 일치했네.","JPN":"残念ながらフィオネ卿。本件について12元老の意向は一致している。","ENG":"I regret to say it, Dame Fione, but all twelve Elders are in agreement.","TWN":"很遺憾，菲奧尼。關於此事，十二位元老的意見是一致的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"심정은 이해하나, 자네의 발언이 현 상황을 뒤엎을 수 있을 것 같지는 않군.","JPN":"気持ちはわかるが、君の発言が今の状況を覆せるものとは思えないな。","ENG":"We understand how you feel, but your words won't overturn this decision.","TWN":"我理解你的心情，但你的發言似乎無法改變當前的局勢。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"열두 원로라니… 설마, 아버님께서 단장님의 퇴임을 동의하셨다는 겁니까?","JPN":"12元老ということは……まさか、父が団長の退任に同意したということですか？","ENG":"Twelve Elders...? Are you saying even Father approved of her removal?","TWN":"十二元老……難道是父親同意了團長的退任嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"잊은 거니? 기사단이 정의라는 신념 아래 뭉칠 수 있었던 건 오직 철저한 규율 덕분이야.","JPN":"忘れたの？　騎士団が正義という信念の下に一つになれたのは、徹底した規律のおかげよ。","ENG":"Have you forgotten? What unites the Order is strict discipline under the belief in justice.","TWN":"你忘了嗎？騎士團能夠在正義的信念下團結在一起，全靠嚴格的紀律。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"그 규율에서 벗어난 기사를 원로원이 기껍게 볼 리가 없지.","JPN":"その規律を破った騎士を元老院が許すわけがない。","ENG":"No Elder would turn a blind eye to someone who breaks that order.","TWN":"元老院怎麼可能會對違反規矩的騎士心生不滿呢。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CARRY_ZODIAC_NULL_NULL","text":{"KOREA":"안 그래, 에스테로사 경?","JPN":"でしょう？　エステロサ卿。","ENG":"Isn't that right, Dame Esterosa?","TWN":"不是嗎，艾斯特洛索？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"정의를 위한 규율은 중요하네.","JPN":"正義のための規律は大事だ。","ENG":"Discipline in pursuit of justice is important.","TWN":"為了正義的紀律是重要的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"허나 규율을 통한 정의는 눈속임에 불과하지.","JPN":"しかし、規律による正義は目くらましにすぎない。","ENG":"But justice built only on rules is an illusion.","TWN":"然而，透過規矩實現的正義不過是障眼法。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"진정 중요한 것이 무엇인지, 늘 눈과 귀를 열고 살피도록 하게.","JPN":"本当に大事なものは何か、常に目を見開き、耳を済まして注意を払うんだ。","ENG":"Always keep your eyes and ears open to what truly matters.","TWN":"要時刻睜開眼睛和耳朵，觀察真正重要的東西。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"왜… 저는 이런 상황에서까지 당신의 가르침을 떠올리고 있는 거죠?","JPN":"なぜ……私はこんな状況ですら、あなたの教えを思い出しているのでしょう。","ENG":"Why... why do I still recall your teachings, even in a moment like this?","TWN":"為什麼……我在這種情況下還會想起你的教誨呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"제가 믿어온 정의가…… 틀렸다는 건가요?","JPN":"私が信じてきた正義は……間違っていたということでしょうか。","ENG":"Does this mean the justice I believed in... was wrong?","TWN":"我一直相信的正義……是錯的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"원로들의 뜻이 그러하니 에스테로사 경은 단장직을 반납하고 버고 소드를 봉환하라!","JPN":"元老院の意志がそうなら、エステロサ卿は団長職を返上し、ヴァルゴソードを騎士団に返すべきだ！","ENG":"As the Elders have decreed, Dame Esterosa must relinquish her command and return the Virgo Sword!","TWN":"既然長老們的意願如此，艾斯特洛索請交還團長職務，並封存布林加夫之劍！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"옳소! 별의 무구를 봉환하라! 그녀에게 책임을 물어야 한다!!","JPN":"そうだ！　星の武具を返せ！　彼女の責任を問うべきだ！","ENG":"Aye! Return the Armament! She must be held accountable!","TWN":"沒錯！召回星之武具！必須追究她的責任！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그녀는 정의를 저버리고 기사단의 명예를 실추시킨 <color=#ffd34c>변절자</color>다!!","JPN":"彼女は正義を捨て、騎士団の名誉を傷つけた<color=#ffd34c>変節者</color>だ！！","ENG":"She betrayed justice and stained the honor of the Order. She is a <color=#ffd34c>traitor</color>!","TWN":"她是背棄正義，玷污騎士團榮譽的<color=#ffd34c>叛徒</color>！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"더는 못 참아! 언제부터 우리가 사람 구하는데 이유를 하나둘씩 따졌어?","JPN":"あったまきたー！　いつから私たちは人を助けるのに理由をつけた？","ENG":"That is enough! Since when did we start needing reasons to save people?!","TWN":"我再也忍不了了！我們什麼時候開始在救人時還要一個個找理由了？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"단장을 바꾸고 싶다면 기사답게 검으로 말해! 얼마든지 받아줄 테니까!","JPN":"団長を変えたいなら、騎士らしく剣で語りなさい！　いくらでも受けて立つから！","ENG":"If you want a new captain, speak through your sword like a true knight! I'll take on any of you!","TWN":"如果想要換團長，就用劍來證明你的騎士精神吧！我隨時奉陪！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"싸, 싸움은 안 돼요, 리브 언니!","JPN":"た、戦いはダメです、リブさん！","ENG":"N-no fighting, Dame Liv!","TWN":"不，不要打架，莉芙姊姊！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하지만, 이대로 가만히 있다가는 단장님이……!!","JPN":"でもこのままだと団長が……！！","ENG":"But if we just sit by like this, Captain will...!","TWN":"但是，如果就這樣不管的話，團長會……！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"죽도 만 번 휘두르기 전에 제가 다른 소양도 길러 놓으라 했죠?","JPN":"1万回の素振りもいいですが、他の勉強も怠らないようにと私、言いましたよね。","ENG":"Didn't I tell you to work on your mind as much as your blade before swinging it ten thousand times?","TWN":"我不是讓你在揮舞竹刀一萬次之前，先培養其他素養嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"문제입니다~. 전통에는 시간이 지나 생긴 풍파가 있기 마련이니, 옛 규범을 따른 주장에는?","JPN":"クイズで～す。伝統というものには、時と共に波風が立つのが常。では、古き規範に従う主張に対して取るべき態度は？","ENG":"Here's the problem. Traditions shift with time. And what do we do with outdated ideals?","TWN":"這是個問題～傳統總是隨著時間的推移而產生波折，那麼遵循舊規範的主張呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"아! 서로 간의 모순을 찾아 해당 부분을 집요하게 파고든다…….","JPN":"あ！　相互の矛盾点を見つけ出して、しつこく突き詰める……","ENG":"Ah! We expose the contradictions and tear them down piece by piece...","TWN":"啊！找到彼此之間的矛盾，並執著地深入探討該部分……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"누, 누님?! 여긴 어떻게?","JPN":"メデイアさん？　どうしてここに？","ENG":"W-wait, M-Medea?! Why are you here?!","TWN":"姊、姊姊？！怎麼會在這裡？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"원로분들이 불렀으니까 왔죠. 제가 여기 오면 안 돼요?","JPN":"元老の方々に呼ばれたからでしょう。私がここに来てはいけない理由でもありますの？","ENG":"The Elders summoned me, of course. Am I not allowed to come?","TWN":"元老們叫我來的，所以我來了。我不能來這裡嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 평소에는 귀찮다고 이런 일에는 신경도 안 쓰면서…….","JPN":"いや、いつもは面倒くさいとこういうことには目もくれないくせに……","ENG":"But you always say this kind of thing is too much hassle...","TWN":"哎，平時總是嫌麻煩，對這種事情根本不關心……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"마, 말이 헛나왔네요. 죄송합니다.","JPN":"く、口が滑りました。すみません。","ENG":"I-I misspoke. I apologize.","TWN":"啊，說錯話了。對不起。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮아요. 민감한 상황이니 그럴 수 있죠~.","JPN":"大丈夫です。微妙な状況ですし、理解しますわ。","ENG":"It's fine. Tensions are high, things slip out.","TWN":"沒關係。這是個敏感的情況，難免會這樣～"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"오오… 저 사람은?","JPN":"おお……あの人は？","ENG":"Wait... is that her?","TWN":"喔喔…那個人是？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"틀림없어. 전 세대 기사 중 한 명인 메데이아 경이야…!","JPN":"間違いない。先代の騎士の一人であるメデイア卿だ……！","ENG":"No doubt about it. That's Dame Medea, one of the previous generation's knights...!","TWN":"沒錯。是上一代騎士之一的美狄亞…！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"이런 자리에서 그대를 보는 것은 오랜만이군, 메데이아 경.","JPN":"このような場でそなたを見るのは久しぶりだな、メデイア卿。","ENG":"It's been some time since we've seen you at a gathering like this, Dame Medea.","TWN":"在這樣的場合見到你，美狄亞，真是久違了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"전임 기사단장 취임식이 마지막이었죠. 그동안 얼굴을 비치지 못해 죄송합니다.","JPN":"前騎士団長の就任式が最後でしたわね。今まで顔を出せず、申し訳ありませんでした。","ENG":"Not since the former captain's inauguration. I apologize for not appearing sooner.","TWN":"上次見面還是在前任騎士團長的就職典禮上。一直沒能露面，真是抱歉。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"별을 추종하는 데이비스의 메데이아.","JPN":"星の追従者、デイヴィスのメデイア。","ENG":"Medea of House Davis, follower of the stars.","TWN":"追隨星辰的美狄亞·戴維斯。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"원로원의 부름을 받아, 가문의 목소리를 전하러 왔습니다.","JPN":"元老院の呼びかけに応じ、デイヴィス家の声を届けに参りました。","ENG":"I come at the Council's request, to speak on behalf of my house.","TWN":"應元老院的召喚，我來傳達家族的聲音。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};